(function () {
  const EMBEDDED_WHITE_LOGO = 'data:image/png;base64,';

  function safeFilename(value) {
    return String(value || '')
      .normalize('NFD')
      .replace(/[̀-ͯ]/g, '')
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/(^-|-$)/g, '') || 'rgcars';
  }

  function cleanList(value) {
    if (Array.isArray(value)) return value.map((item) => String(item).trim()).filter(Boolean);
    return String(value || '')
      .split(/\r?\n|,/) 
      .map((item) => item.trim().replace(/^[-•·]\s*/, ''))
      .filter(Boolean);
  }

  function specRows(vehicle) {
    return [
      ['Modelo', vehicle.title || [vehicle.brand, vehicle.model, vehicle.year].filter(Boolean).join(' ') || 'Vehículo'],
      ['Motor', window.RGShared.textOrDash(vehicle.engine)],
      ['Transmisión', window.RGShared.textOrDash(vehicle.transmission)],
      ['Tracción', window.RGShared.textOrDash(vehicle.drivetrain)],
      ['Año de fabricación', window.RGShared.textOrDash(vehicle.year)],
      ['Kilometraje', window.RGShared.formatKm(vehicle.km)],
      ['Patente', window.RGShared.textOrDash(vehicle.plate)],
      ['Color', window.RGShared.textOrDash(vehicle.color)],
      ['Cantidad de puertas', window.RGShared.textOrDash(vehicle.doors)],
      ['Combustible', window.RGShared.textOrDash(vehicle.fuel_type)],
      ['Estado', window.RGShared.textOrDash(vehicle.vehicle_condition || window.RGShared.statusLabel(vehicle.status))],
      ['Precio', window.RGShared.formatPrice(vehicle.price, vehicle.currency)],
    ].filter(([, value]) => value && value !== '-');
  }

  function addFittedImage(doc, dataUrl, x, y, w, h) {
    if (!dataUrl) return;
    const props = doc.getImageProperties(dataUrl);
    const ratio = Math.min(w / props.width, h / props.height);
    const drawW = props.width * ratio;
    const drawH = props.height * ratio;
    const dx = x + (w - drawW) / 2;
    const dy = y + (h - drawH) / 2;
    const format = (props.fileType || 'JPEG').toUpperCase();
    doc.addImage(dataUrl, format, dx, dy, drawW, drawH, undefined, 'FAST');
  }

  async function download(vehicle) {
    if (!window.jspdf?.jsPDF) {
      throw new Error('La librería de PDF no está disponible.');
    }

    const { jsPDF } = window.jspdf;
    const doc = new jsPDF({ unit: 'mm', format: 'a4', compress: true });
    const imageUrl = window.RGShared.firstImage(vehicle);

    let heroImage = null;
    let logoImage = EMBEDDED_WHITE_LOGO;

    try {
      if (imageUrl) heroImage = await window.RGShared.loadImageAsDataUrl(imageUrl);
    } catch (error) {
      console.warn('No se pudo cargar la imagen principal para la ficha:', error.message);
    }

    try {
      logoImage = await window.RGShared.loadImageAsDataUrl('./imagenes/isotipo-white.png');
    } catch (error) {
      console.warn('No se pudo cargar el logo blanco, se usa la versión embebida:', error.message);
    }

    const equipment = cleanList(vehicle.featured_equipment);
    const specs = specRows(vehicle);
    const title = vehicle.title || [vehicle.brand, vehicle.model, vehicle.year].filter(Boolean).join(' ') || 'Vehículo';
    const subtitle = [vehicle.brand, vehicle.model].filter(Boolean).join(' · ') || 'RG Cars TDF';
    const description = vehicle.description?.trim()
      ? vehicle.description.trim()
      : 'Consultá disponibilidad actualizada, formas de pago, permutas y condiciones comerciales con el equipo de RG Cars TDF.';

    doc.setFillColor(255, 255, 255);
    doc.rect(0, 0, 210, 297, 'F');
    doc.setFillColor(200, 16, 46);
    doc.rect(0, 0, 210, 7, 'F');

    doc.setFillColor(15, 23, 42);
    doc.roundedRect(14, 14, 182, 24, 8, 8, 'F');
    if (logoImage) addFittedImage(doc, logoImage, 18, 18, 42, 14);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(17);
    doc.text('Ficha técnica', 188, 22, { align: 'right' });
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(9.5);
    doc.setTextColor(214, 220, 231);
    doc.text('Formato comercial de unidad', 188, 28.5, { align: 'right' });

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(20);
    doc.setTextColor(15, 23, 42);
    const titleLines = doc.splitTextToSize(title, 120);
    doc.text(titleLines.slice(0, 2), 16, 52);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10.5);
    doc.setTextColor(100, 116, 139);
    doc.text(subtitle, 16, 61 + (titleLines.length > 1 ? 7 : 0));

    doc.setFillColor(246, 248, 252);
    doc.roundedRect(16, 70, 82, 58, 6, 6, 'F');
    if (heroImage) {
      addFittedImage(doc, heroImage, 18, 72, 78, 54);
    } else {
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(11);
      doc.setTextColor(100, 116, 139);
      doc.text('Sin imagen principal', 57, 101, { align: 'center' });
    }

    doc.setFillColor(248, 250, 252);
    doc.setDrawColor(226, 232, 240);
    doc.roundedRect(106, 70, 88, 58, 6, 6, 'FD');
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(9.5);
    doc.setTextColor(100, 116, 139);
    doc.text('Precio publicado', 150, 83, { align: 'center' });
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(18);
    doc.setTextColor(15, 23, 42);
    doc.text(window.RGShared.formatPrice(vehicle.price, vehicle.currency), 150, 95, { align: 'center' });
    doc.setFontSize(10.5);
    doc.setTextColor(71, 85, 105);
    doc.text(`Estado publicación: ${window.RGShared.statusLabel(vehicle.status)}`, 150, 106, { align: 'center' });
    doc.text(vehicle.financing_enabled ? 'Unidad con financiación disponible' : 'Consultar alternativas de financiación', 150, 114, { align: 'center' });

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(13);
    doc.setTextColor(15, 23, 42);
    doc.text('Datos principales', 16, 142);

    let y = 150;
    specs.forEach(([label, value], index) => {
      const col = index % 2;
      const row = Math.floor(index / 2);
      const x = col === 0 ? 16 : 106;
      const boxY = y + row * 14;
      doc.setFillColor(248, 250, 252);
      doc.roundedRect(x, boxY - 6.5, 88, 11, 4, 4, 'F');
      doc.setFont('helvetica', 'bold');
      doc.setFontSize(9);
      doc.setTextColor(30, 41, 59);
      doc.text(`${label}:`, x + 4, boxY);
      doc.setFont('helvetica', 'normal');
      doc.setTextColor(71, 85, 105);
      const valueX = x + 34;
      const wrapped = doc.splitTextToSize(String(value), 49);
      doc.text(wrapped[0], valueX, boxY);
    });

    const specsRows = Math.ceil(specs.length / 2);
    y = y + specsRows * 14 + 10;

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(13);
    doc.setTextColor(15, 23, 42);
    doc.text('Equipamiento destacado', 16, y);
    y += 8;

    if (equipment.length) {
      equipment.forEach((item) => {
        if (y > 252) {
          doc.addPage();
          y = 22;
        }
        doc.setFillColor(248, 250, 252);
        doc.roundedRect(16, y - 5, 178, 9, 3, 3, 'F');
        doc.setFont('helvetica', 'normal');
        doc.setFontSize(10);
        doc.setTextColor(51, 65, 85);
        const bullet = `• ${item}`;
        const line = doc.splitTextToSize(bullet, 168)[0];
        doc.text(line, 20, y);
        y += 10;
      });
    } else {
      doc.setFont('helvetica', 'normal');
      doc.setFontSize(10);
      doc.setTextColor(100, 116, 139);
      doc.text('Esta unidad no tiene equipamiento destacado cargado todavía.', 16, y);
      y += 10;
    }

    if (y > 230) {
      doc.addPage();
      y = 22;
    }

    doc.setFont('helvetica', 'bold');
    doc.setFontSize(13);
    doc.setTextColor(15, 23, 42);
    doc.text('Descripción comercial', 16, y + 4);
    y += 12;
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10.3);
    doc.setTextColor(71, 85, 105);
    const descLines = doc.splitTextToSize(description, 176);
    doc.text(descLines.slice(0, 9), 16, y);
    y += Math.min(descLines.length, 9) * 5.2 + 8;

    if (y > 245) {
      doc.addPage();
      y = 22;
    }

    doc.setFillColor(15, 23, 42);
    doc.roundedRect(16, y, 178, 28, 6, 6, 'F');
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(11.5);
    doc.setTextColor(255, 255, 255);
    doc.text('Contacto comercial', 24, y + 10);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(10);
    doc.text(`WhatsApp: +${window.RG.WHATSAPP}`, 24, y + 18);
    doc.text('RG Cars TDF · Sarmiento 2760 · Río Grande, Tierra del Fuego', 24, y + 24);

    doc.setTextColor(107, 114, 128);
    doc.setFontSize(8.5);
    doc.text('Documento generado automáticamente desde el panel de RG Cars TDF.', 16, 286);
    doc.text('La disponibilidad, el precio y las condiciones comerciales pueden actualizarse sin previo aviso.', 16, 291);

    const fileName = `ficha-${safeFilename(vehicle.brand || '')}-${safeFilename(vehicle.model || vehicle.title || '')}-${vehicle.year || 'rgcars'}.pdf`;
    doc.save(fileName);
    return fileName;
  }

  window.RGFicha = { download };
})();
